import React, { Fragment } from 'react';
import { Row, Col } from '..';
import { Divider } from '../../divider';
import './index.less';

export default {
  title: 'Components/Grid/临时示例',
};

interface DemoBoxProps {
  value: string;
  children: any;
  secondary?: boolean;
}

const DemoBox = (props: DemoBoxProps) => {
  const { value, secondary, children } = props;
  const cls = `height-${value}`;
  const classes = `${cls} ${secondary ? `${cls}-secondary` : ''}`;
  return <div className={classes}>{children}</div>;
};

const renderAlignDemo = (align: 'top' | 'middle' | 'bottom') => (
  <Fragment>
    <Divider text={`align-${align}`} />
    <Row align={align}>
      <Col span={8}>
        <DemoBox value="50">align-{align}-col-1</DemoBox>
      </Col>
      <Col offset={4} span={2}>
        <DemoBox value="150">align-{align}-col-2</DemoBox>
      </Col>
      <Col offset={2} span={8}>
        <DemoBox value="20">align-{align}-col-3</DemoBox>
      </Col>
    </Row>
  </Fragment>
);

